def create_response(status_code, body):
    """Create HTTP response with CORS headers"""
    return {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Headers': 'Content-Type,X-Amz-Date,Authorization,X-Api-Key,X-Amz-Security-Token',
            'Access-Control-Allow-Methods': 'GET,POST,PUT,DELETE,OPTIONS',
            'Access-Control-Max-Age': '3600'
        },
        'body': json.dumps(body)
    }

def lambda_handler(event, context):
    """Main Lambda handler for user data API"""
    
    # Handle OPTIONS requests for CORS preflight
    if event.get('httpMethod') == 'OPTIONS':
        return create_response(200, {'message': 'CORS preflight successful'})
    
    # Get HTTP method and path
    http_method = event.get('httpMethod', 'GET')
    path = event.get('path', '/')
    path_parameters = event.get('pathParameters') or {}
    query_parameters = event.get('queryStringParameters') or {}
    
    try:
        # Route: GET /users - Get all users
        if http_method == 'GET' and path == '/users':
            users_list = list(USERS.values())
            
            # Optional filtering by role
            role_filter = query_parameters.get('role')
            if role_filter:
                users_list = [u for u in users_list if u['role'] == role_filter]
            
            return create_response(200, {
                'users': users_list,
                'count': len(users_list),
                'timestamp': datetime.utcnow().isoformat() + 'Z'
            })
        
        # Route: GET /users/{userId} - Get specific user
        elif http_method == 'GET' and '/users/' in path:
            user_id = path_parameters.get('userId')
            
            if not user_id:
                return create_response(400, {
                    'error': 'User ID is required',
                    'message': 'Please provide a valid user ID'
                })
            
            user = USERS.get(user_id)
            
            if not user:
                return create_response(404, {
                    'error': 'User not found',
                    'message': f'No user exists with ID: {user_id}'
                })
            
            return create_response(200, {
                'user': user,
                'timestamp': datetime.utcnow().isoformat() + 'Z'
            })
        
        # Route: POST /users - Create new user (simulated)
        elif http_method == 'POST' and path == '/users':
            try:
                body = json.loads(event.get('body', '{}'))
            except json.JSONDecodeError:
                return create_response(400, {
                    'error': 'Invalid JSON',
                    'message': 'Request body must be valid JSON'
                })
            
            # Validate required fields
            required_fields = ['name', 'email']
            missing_fields = [field for field in required_fields if field not in body]
            
            if missing_fields:
                return create_response(400, {
                    'error': 'Missing required fields',
                    'message': f'Required fields: {", ".join(missing_fields)}'
                })
            
            # Create new user
            new_id = str(len(USERS) + 1)
            new_user = {
                'id': new_id,
                'name': body['name'],
                'email': body['email'],
                'role': body.get('role', 'user'),
                'created_at': datetime.utcnow().isoformat() + 'Z'
            }
            
            USERS[new_id] = new_user
            
            return create_response(201, {
                'message': 'User created successfully',
                'user': new_user
            })
        
        # Route: PUT /users/{userId} - Update user (simulated)
        elif http_method == 'PUT' and '/users/' in path:
            user_id = path_parameters.get('userId')
            
            if not user_id or user_id not in USERS:
                return create_response(404, {
                    'error': 'User not found',
                    'message': f'No user exists with ID: {user_id}'
                })
            
            try:
                body = json.loads(event.get('body', '{}'))
            except json.JSONDecodeError:
                return create_response(400, {
                    'error': 'Invalid JSON',
                    'message': 'Request body must be valid JSON'
                })
            
            # Update user
            user = USERS[user_id].copy()
            if 'name' in body:
                user['name'] = body['name']
            if 'email' in body:
                user['email'] = body['email']
            if 'role' in body:
                user['role'] = body['role']
            
            user['updated_at'] = datetime.utcnow().isoformat() + 'Z'
            USERS[user_id] = user
            
            return create_response(200, {
                'message': 'User updated successfully',
                'user': user
            })
        
        # Route: DELETE /users/{userId} - Delete user (simulated)
        elif http_method == 'DELETE' and '/users/' in path:
            user_id = path_parameters.get('userId')
            
            if not user_id or user_id not in USERS:
                return create_response(404, {
                    'error': 'User not found',
                    'message': f'No user exists with ID: {user_id}'
                })
            
            deleted_user = USERS.pop(user_id)
            
            return create_response(200, {
                'message': 'User deleted successfully',
                'user': deleted_user
            })
        
        # Route not found
        else:
            return create_response(404, {
                'error': 'Route not found',
                'message': f'No route matches {http_method} {path}'
            })
    
    except Exception as e:
        return create_response(500, {
            'error': 'Internal server error',
            'message': str(e)
        })